const express = require('express');
const crypto = require('crypto');

const app = express();
const port = 3000;

app.post('/webhook', express.raw({ type: 'application/json' }), (req, res) => {
  const signatureHeader = req.headers['x-prembly-signature'];

  if (!signatureHeader) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  const secret = process.env.PREMBLY_API_KEY;
  if (!secret) {
    console.error('PREMBLY_API_KEY environment variable is missing.');
    // The prompt just says "If the signatures do NOT match or the header is missing, respond with 401 Unauthorized"
    // so we should probably respond with 401 if secret is missing to be safe, or 500.
    return res.status(500).json({ error: 'Internal server error' });
  }

  try {
    const computedSignature = crypto
      .createHmac('sha256', secret)
      .update(req.body)
      .digest('base64');

    if (signatureHeader === computedSignature) {
      return res.status(200).json({ status: 'success' });
    } else {
      return res.status(401).json({ error: 'Invalid signature' });
    }
  } catch (err) {
    return res.status(401).json({ error: 'Invalid signature' });
  }
});

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

